### E2E Test Additions (\`scripts/e2e_test.sh\`)
\`\`\`bash
test_progress_indicators() {
    log "INFO" "PROGRESS" "Testing progress indicator behavior..."

    # Test spinner appears during probe
    local stderr_file="$LOG_DIR/probe_stderr.txt"
    RCH_MOCK_SSH=1 "$RCH" workers probe mock-worker 2>"$stderr_file"
    if ! grep -q "mock-worker" "$stderr_file"; then
        log "FAIL" "PROGRESS" "No worker name in progress output"
        return 1
    fi
    log "INFO" "PROGRESS" "Spinner test OK"

    # Test no animation codes when piped
    local output
    output=$(RCH_MOCK_SSH=1 "$RCH" workers probe --all 2>&1 | cat)
    if echo "$output" | grep -q $'\x1b\[?25'; then
        log "FAIL" "PROGRESS" "Animation codes present in piped output"
        return 1
    fi
    log "INFO" "PROGRESS" "Pipe detection OK"

    # Test progress completes without hanging
    if ! timeout 10 bash -c 'RCH_MOCK_SSH=1 '"$RCH"' workers probe --all 2>&1' > /dev/null; then
        log "FAIL" "PROGRESS" "Progress indicators caused hang"
        return 1
    fi
    log "INFO" "PROGRESS" "No hang test OK"
}
