 {"id":"remote_compilation_helper-6qs","title":"Implement local toolchain version detection in hook","description":"## Parent Epic: Automatic Toolchain Synchronization (remote_compilation_helper-ayn)

## Task Description

Implement detection of the local Rust toolchain version in the hook. This version will be sent to the daemon/worker to ensure compilation uses a matching toolchain.

## Design

### Version Detection Approaches

1. **Parse rustc --version output**
   ```
   rustc 1.76.0-nightly (abc123def 2024-01-15)
   rustc 1.75.0 (82e1608df 2023-12-21)
   ```

2. **Parse rust-toolchain.toml (if present)**
   ```toml
   [toolchain]
   channel = "nightly-2024-01-15"
   ```

3. **Use rustup show active-toolchain**
   ```
   nightly-2024-01-15-x86_64-unknown-linux-gnu (overridden by '/project/rust-toolchain.toml')
   ```

### Implementation
```rust
// In rch/src/toolchain.rs (new file) or rch/src/classify.rs

use std::process::Command;
use std::path::Path;

/// Detected Rust toolchain information
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ToolchainInfo {
    /// The channel: "stable", "beta", "nightly", or specific version
    pub channel: String,
    /// Optional date for nightly/beta: "2024-01-15"
    pub date: Option<String>,
    /// Full version string from rustc --version
    pub full_version: String,
}

impl ToolchainInfo {
    /// Format for rustup run command
    pub fn rustup_toolchain(&self) -> String {
        match &self.date {
            Some(date) => format!("{}-{}", self.channel, date),
            None => self.channel.clone(),
        }
    }
}

/// Detect the active Rust toolchain for a project
pub fn detect_toolchain(project_root: &Path) -> Result<ToolchainInfo, ToolchainError> {
    // 1. Check for rust-toolchain.toml override
    let toolchain_file = project_root.join("rust-toolchain.toml");
    if toolchain_file.exists() {
        if let Ok(info) = parse_toolchain_file(&toolchain_file) {
            return Ok(info);
        }
    }

    // 2. Check for rust-toolchain (legacy format)
    let legacy_file = project_root.join("rust-toolchain");
    if legacy_file.exists() {
        if let Ok(info) = parse_legacy_toolchain_file(&legacy_file) {
            return Ok(info);
        }
    }

    // 3. Fall back to rustc --version
    detect_from_rustc()
}

fn parse_toolchain_file(path: &Path) -> Result<ToolchainInfo, ToolchainError> {
    let content = std::fs::read_to_string(path)?;
    let toml: toml::Value = content.parse()?;

    let channel = toml
        .get("toolchain")
        .and_then(|t| t.get("channel"))
        .and_then(|c| c.as_str())
        .ok_or(ToolchainError::InvalidFormat)?;

    parse_channel_string(channel)
}

fn parse_channel_string(channel: &str) -> Result<ToolchainInfo, ToolchainError> {
    // Parse: "nightly-2024-01-15" or "stable" or "1.75.0"
    if channel.starts_with("nightly-") {
        let date = channel.strip_prefix("nightly-").unwrap();
        Ok(ToolchainInfo {
            channel: "nightly".to_string(),
            date: Some(date.to_string()),
            full_version: channel.to_string(),
        })
    } else if channel.starts_with("beta-") {
        let date = channel.strip_prefix("beta-").unwrap();
        Ok(ToolchainInfo {
            channel: "beta".to_string(),
            date: Some(date.to_string()),
            full_version: channel.to_string(),
        })
    } else if channel == "stable" || channel == "beta" || channel == "nightly" {
        Ok(ToolchainInfo {
            channel: channel.to_string(),
            date: None,
            full_version: channel.to_string(),
        })
    } else {
        // Specific version like "1.75.0"
        Ok(ToolchainInfo {
            channel: channel.to_string(),
            date: None,
            full_version: channel.to_string(),
        })
    }
}

fn detect_from_rustc() -> Result<ToolchainInfo, ToolchainError> {
    let output = Command::new("rustc")
        .arg("--version")
        .output()?;

    let version_str = String::from_utf8_lossy(&output.stdout);
    // Parse: "rustc 1.76.0-nightly (abc123def 2024-01-15)"
    parse_rustc_version(&version_str)
}

fn parse_rustc_version(version_str: &str) -> Result<ToolchainInfo, ToolchainError> {
    // Regex: rustc (\d+\.\d+\.\d+)(-nightly|-beta)? \(([a-f0-9]+) (\d{4}-\d{2}-\d{2})\)
    let re = regex::Regex::new(
        r"rustc (\d+\.\d+\.\d+)(-nightly|-beta)? \(([a-f0-9]+) (\d{4}-\d{2}-\d{2})\)"
    )?;

    if let Some(caps) = re.captures(version_str) {
        let version = caps.get(1).unwrap().as_str();
        let channel_suffix = caps.get(2).map(|m| m.as_str());
        let date = caps.get(4).map(|m| m.as_str().to_string());

        let channel = match channel_suffix {
            Some("-nightly") => "nightly".to_string(),
            Some("-beta") => "beta".to_string(),
            None => "stable".to_string(),
        };

        Ok(ToolchainInfo {
            channel,
            date,
            full_version: version_str.trim().to_string(),
        })
    } else {
        Err(ToolchainError::ParseError(version_str.to_string()))
    }
}

#[derive(Debug, thiserror::Error)]
pub enum ToolchainError {
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),
    #[error("Invalid toolchain file format")]
    InvalidFormat,
    #[error("Failed to parse version: {0}")]
    ParseError(String),
    #[error("TOML parse error: {0}")]
    Toml(#[from] toml::de::Error),
    #[error("Regex error: {0}")]
    Regex(#[from] regex::Error),
}
