+              ))}
+            </ul>
+          </div>
+        )}
+
+        {/* Workers Section */}
+        <section>
+          <h2 className="text-lg font-semibold text-foreground mb-4">Workers</h2>
+          <WorkersGrid workers={status.workers} />
+        </section>
+
+        {/* Build History Section */}
